// FilterModel.ets
//
// Supporting value types for filtering, recommendation ranking, calendar
// rendering, and the share card payload.

import { Dish, DifficultyKey, MealKey, MoodKey, TasteKey } from './DishModel';

// mood/meal/difficulty are single-select (null = unconstrained);
// tastes are multi-select (empty = unconstrained).
export interface FilterCriteria {
  mood: MoodKey | null;
  meal: MealKey | null;
  difficulty: DifficultyKey | null;
  tastes: TasteKey[];
}

export function emptyCriteria(): FilterCriteria {
  return { mood: null, meal: null, difficulty: null, tastes: [] } as FilterCriteria;
}

export function isEmptyCriteria(c: FilterCriteria): boolean {
  return c.mood === null && c.meal === null && c.difficulty === null && c.tastes.length === 0;
}

// Ranked dish from ingredient-based recommendation.
export interface ScoredDish {
  dish: Dish;
  matched: number;   // how many of the dish's ingredients the user owns
  coverage: number;  // matched / dish.ingredients.length
}

export interface CalendarDay {
  dateKey: string; // YYYY-MM-DD
  dayNumber: number;
  inMonth: boolean;
  hasCheckin: boolean;
}

export interface ShareCard {
  date: string;      // formatted date
  dishName: string;
  streak: number;
  theme: string;     // theme key, e.g. 'sage'
}

