// DateUtil.ets
//
// Small, dependency-free date helpers. App code is free to use Date directly;
// these centralize the YYYY-MM-DD key and label formats used by check-in logic.

export class DateUtil {
  static pad2(n: number): string {
    return n < 10 ? `0${n}` : `${n}`;
  }

  static toKey(d: Date): string {
    return `${d.getFullYear()}-${DateUtil.pad2(d.getMonth() + 1)}-${DateUtil.pad2(d.getDate())}`;
  }

  static todayKey(): string {
    return DateUtil.toKey(new Date());
  }

  static keyToDate(key: string): Date {
    const parts: string[] = key.split('-');
    return new Date(Number.parseInt(parts[0], 10),
      Number.parseInt(parts[1], 10) - 1,
      Number.parseInt(parts[2], 10));
  }

  static dayLabel(key: string): string {
    const d: Date = DateUtil.keyToDate(key);
    const weekdays: string[] = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    return `${DateUtil.pad2(d.getMonth() + 1)}月${DateUtil.pad2(d.getDate())}日 ${weekdays[d.getDay()]}`;
  }

  static formattedToday(): string {
    return DateUtil.dayLabel(DateUtil.todayKey());
  }

  // Time-aware greeting for the home header.
  static greetingFor(date: Date = new Date()): string {
    const h: number = date.getHours();
    if (h < 6) {
      return '夜深了，吃点暖的';
    } else if (h < 11) {
      return '早安，今天吃点什么';
    } else if (h < 14) {
      return '中午好，开饭啦';
    } else if (h < 18) {
      return '下午茶时间到';
    } else if (h < 22) {
      return '晚上好，今夜吃什么';
    }
    return '夜宵局，安排';
  }

  // Returns YYYY-MM-DD for (today - offsetDays).
  static keyOffsetDays(offsetDays: number): string {
    const d: Date = new Date();
    d.setDate(d.getDate() + offsetDays);
    return DateUtil.toKey(d);
  }

  static isWithinPastDays(key: string, days: number): boolean {
    const target: number = DateUtil.keyToDate(key).getTime();
    const cutoff: number = DateUtil.keyToDate(DateUtil.keyOffsetDays(-days + 1)).getTime();
    return target >= cutoff;
  }
}

