// DishService.ets
//
// Stateless access to the offline dish library plus the decision algorithms:
//  - wheel segment picking (random subset for the spin wheel)
//  - filter by mood / meal / difficulty / tastes
//  - ingredient-coverage recommendation with random jitter

import { Dish } from '../model/DishModel';
import { DishService as _unused } from '../data/DishDataset';
import { DISHES } from '../data/DishDataset';
import { FilterCriteria, ScoredDish } from '../model/FilterModel';

export class DishService {
  static all(): Dish[] {
    return DISHES;
  }

  static findById(id: string): Dish | null {
    for (const d of DISHES) {
      if (d.id === id) {
        return d;
      }
    }
    return null;
  }

  // Fisher–Yates shuffle on a copy.
  static shuffle<T>(input: T[]): T[] {
    const out: T[] = input.slice();
    for (let i: number = out.length - 1; i > 0; i--) {
      const j: number = Math.floor(Math.random() * (i + 1));
      const tmp: T = out[i];
      out[i] = out[j];
      out[j] = tmp;
    }
    return out;
  }

  // Pick N distinct dishes for the spin wheel. If the library is smaller than N,
  // return all of it shuffled.
  static pickWheelSegments(count: number): Dish[] {
    const shuffled: Dish[] = DishService.shuffle(DISHES);
    if (shuffled.length <= count) {
      return shuffled;
    }
    return shuffled.slice(0, count);
  }

  static matchesFilter(d: Dish, c: FilterCriteria): boolean {
    if (c.mood !== null && !d.moods.includes(c.mood)) {
      return false;
    }
    if (c.meal !== null && !d.meals.includes(c.meal)) {
      return false;
    }
    if (c.difficulty !== null && d.difficulty !== c.difficulty) {
      return false;
    }
    if (c.tastes.length > 0) {
      let any: boolean = false;
      for (const t of c.tastes) {
        if (d.tastes.includes(t)) {
          any = true;
          break;
        }
      }
      if (!any) {
        return false;
      }
    }
    return true;
  }

  static filter(c: FilterCriteria): Dish[] {
    const out: Dish[] = [];
    for (const d of DISHES) {
      if (DishService.matchesFilter(d, c)) {
        out.push(d);
      }
    }
    return out;
  }

  // Rank dishes by how many of their required ingredients the user owns.
  // Only dishes with at least one matched ingredient are returned, sorted by
  // coverage desc; ties broken by random jitter for variety on refresh.
  static recommend(ingredients: string[]): ScoredDish[] {
    const owned: Set<string> = new Set<string>(ingredients.map((s: string) => s.trim()));
    const scored: ScoredDish[] = [];
    for (const d of DISHES) {
      let matched: number = 0;
      for (const ing of d.ingredients) {
        if (owned.has(ing)) {
          matched++;
        }
      }
      if (matched > 0) {
        const coverage: number = d.ingredients.length === 0 ? 0 : matched / d.ingredients.length;
        scored.push({ dish: d, matched, coverage } as ScoredDish);
      }
    }
    scored.sort((a: ScoredDish, b: ScoredDish) => {
      if (b.coverage !== a.coverage) {
        return b.coverage - a.coverage;
      }
      if (b.matched !== a.matched) {
        return b.matched - a.matched;
      }
      return Math.random() - 0.5;
    });
    return scored;
  }

  static pickRandom(): Dish {
    const idx: number = Math.floor(Math.random() * DISHES.length);
    return DISHES[idx];
  }
}

