// FridgeService.ets
//
// Owns the user's fridge ingredient list. Loads from preferences on init,
// mutates in memory synchronously, and persists asynchronously.

import { LocalStore } from './LocalStore';

const KEY: string = 'fridge_ingredients';

export class FridgeService {
  private static instance: FridgeService | null = null;
  private store: LocalStore = LocalStore.getInstance();
  private items: string[] = [];
  private loaded: boolean = false;

  static getInstance(): FridgeService {
    if (FridgeService.instance === null) {
      FridgeService.instance = new FridgeService();
    }
    return FridgeService.instance;
  }

  async load(): Promise<string[]> {
    if (this.loaded) {
      return this.items;
    }
    const stored: string[] | null = await this.store.readJSON<string[]>(KEY);
    this.items = stored !== null ? stored : [];
    this.loaded = true;
    return this.items;
  }

  list(): string[] {
    return this.items;
  }

  count(): number {
    return this.items.length;
  }

  // Returns true if added (false when empty/duplicate/whitespace).
  add(raw: string): boolean {
    const name: string = raw.trim();
    if (name.length === 0) {
      return false;
    }
    if (this.items.indexOf(name) >= 0) {
      return false;
    }
    this.items.push(name);
    this.persist();
    return true;
  }

  removeAt(index: number): void {
    if (index < 0 || index >= this.items.length) {
      return;
    }
    this.items.splice(index, 1);
    this.persist();
  }

  removeByName(name: string): void {
    const idx: number = this.items.indexOf(name);
    if (idx >= 0) {
      this.items.splice(idx, 1);
      this.persist();
    }
  }

  clearAll(): void {
    this.items = [];
    this.persist();
  }

  private persist(): void {
    this.store.writeJSON(KEY, this.items as object).catch(() => {});
  }
}

