    this.records = stored !== null ? stored : [];
    this.loaded = true;
    return this.records;
  }

  all(): CheckinRecord[] {
    return this.records;
  }

  // Add a record. dateKey defaults to today; past dates are allowed only within
  // the last BACKFILL_DAYS days (spec FR-4: 补打过去 7 天内).
  add(dateKey: string, meal: MealKey, dishName: string, note: string): CheckinRecord | null {
    const key: string = dateKey.length > 0 ? dateKey : DateUtil.todayKey();
    if (key !== DateUtil.todayKey() && !DateUtil.isWithinPastDays(key, BACKFILL_DAYS)) {
      return null;
    }
    const name: string = dishName.trim();
    if (name.length === 0) {
      return null;
    }
    const record: CheckinRecord = {
      id: IdUtil.next('checkin'),
      date: key,
      meal,
      dishName: name,
      note: note.trim(),
      shared: false,
    } as CheckinRecord;
    this.records.push(record);
    this.persist();
    return record;
  }

  remove(id: string): void {
    const next: CheckinRecord[] = [];
    for (const r of this.records) {
      if (r.id !== id) {
        next.push(r);
      }
    }
    this.records = next;
    this.persist();
  }

  markShared(id: string): void {
    for (const r of this.records) {
      if (r.id === id) {
        r.shared = true;
      }
    }
    this.persist();
  }

  // Sorted newest first.
  history(): CheckinRecord[] {
    const sorted: CheckinRecord[] = this.records.slice();
    sorted.sort((a: CheckinRecord, b: CheckinRecord) => {
      if (a.date !== b.date) {
        return a.date < b.date ? 1 : -1;
      }
      return a.id < b.id ? 1 : -1;
    });
    return sorted;
  }

  recent(limit: number): CheckinRecord[] {
    return this.history().slice(0, limit);
  }

  recordsForDate(dateKey: string): CheckinRecord[] {
    const out: CheckinRecord[] = [];
    for (const r of this.records) {
      if (r.date === dateKey) {
        out.push(r);
      }
    }
    return out;
  }

  // Latest record for today, or null if none yet.
  todayLatest(): CheckinRecord | null {
    const today: CheckinRecord[] = this.recordsForDate(DateUtil.todayKey());
    if (today.length === 0) {
      return null;
    }
    return today[today.length - 1];
  }

  hasCheckedIn(dateKey: string): boolean {
    return this.recordsForDate(dateKey).length > 0;
  }

  // Current consecutive-day streak. Counts back from today (or yesterday if
  // today has no record yet) while each day has at least one check-in.
  streak(): number {
    const checked: Set<string> = new Set<string>();
    for (const r of this.records) {
      checked.add(r.date);
    }
    let streak: number = 0;
    let offset: number = 0;
    if (!checked.has(DateUtil.todayKey())) {
      offset = -1; // allow yesterday to still anchor an active streak
    }
    while (true) {
      const key: string = DateUtil.keyOffsetDays(-streak + offset);
      if (checked.has(key)) {
        streak++;
      } else {
        break;
      }
    }
    return streak;
  }

  // Calendar days for the current month with check-in status.
  calendar(): CalendarDay[] {
    const now: Date = new Date();
    const year: number = now.getFullYear();
    const month: number = now.getMonth();
    const lastDay: number = new Date(year, month + 1, 0).getDate();
    const days: CalendarDay[] = [];
    for (let day: number = 1; day <= lastDay; day++) {
      const key: string = `${year}-${DateUtil.pad2(month + 1)}-${DateUtil.pad2(day)}`;
      days.push({
        dateKey: key,
        dayNumber: day,
        inMonth: true,
        hasCheckin: this.hasCheckedIn(key),
      } as CalendarDay);
    }
    return days;
  }

  canBackfill(dateKey: string): boolean {
    if (dateKey === DateUtil.todayKey()) {
      return true;
    }
    return DateUtil.isWithinPastDays(dateKey, BACKFILL_DAYS);
  }

  private persist(): void {
    this.store.writeJSON(KEY, this.records as object).catch(() => {});
  }
}

