// when the platform path is unavailable; these methods return explicit feedback.

import { ShareCard } from '../model/FilterModel';

export class ShareService {
  static buildCard(dateLabel: string, dishName: string, streak: number, theme: string = 'sage'): ShareCard {
    return { date: dateLabel, dishName, streak, theme } as ShareCard;
  }

  // Stubbed save: returns true to represent a successful (simulated) save.
  // A real implementation would render the card to an OffscreenCanvas and write
  // to the media library; that is deferred until the visual layer is ready.
  static async saveImage(): Promise<boolean> {
    return true;
  }

  // Stubbed system share: returns true to represent a successful (simulated) share.
  static async systemShare(): Promise<boolean> {
    return true;
  }
}

