// DishModel.ets
//
// Core domain model for the "今天吃什么" decision app.
// String-literal unions keep semantic IDs / event contexts (from ui-tree.json)
// aligned with in-memory types without enum<->string conversion noise.
//
// Label lookups are implemented as functions rather than Record literals so the
// values satisfy ArkTS strict object-literal typing (arkts-no-untyped-obj-literals).

export type MoodKey = 'happy' | 'tired' | 'indulgent' | 'light' | 'rushed';
export type MealKey = 'breakfast' | 'lunch' | 'dinner' | 'supper';
export type DifficultyKey = 'easy' | 'normal' | 'hard';
export type TasteKey = 'spicy' | 'sweet' | 'sour' | 'savory';

export interface Dish {
  id: string;
  name: string;
  ingredients: string[];
  difficulty: DifficultyKey;
  tastes: TasteKey[];
  meals: MealKey[];
  moods: MoodKey[];
  tags: string[];
  imageHint: string;
}

export function moodLabel(m: MoodKey): string {
  switch (m) {
    case 'happy': return '开心';
    case 'tired': return '疲惫';
    case 'indulgent': return '想放纵';
    case 'light': return '想清淡';
    case 'rushed': return '赶时间';
    default: return '开心';
  }
}

export function mealLabel(m: MealKey): string {
  switch (m) {
    case 'breakfast': return '早餐';
    case 'lunch': return '午餐';
    case 'dinner': return '晚餐';
    case 'supper': return '夜宵';
    default: return '午餐';
  }
}

export function difficultyLabel(d: DifficultyKey): string {
  switch (d) {
    case 'easy': return '快手';
    case 'normal': return '家常';
    case 'hard': return '进阶';
    default: return '家常';
  }
}

export function tasteLabel(t: TasteKey): string {
  switch (t) {
    case 'spicy': return '辣';
    case 'sweet': return '甜';
    case 'sour': return '酸';
    case 'savory': return '咸鲜';
    default: return '咸鲜';
  }
}

export const MOOD_KEYS: MoodKey[] = ['happy', 'tired', 'indulgent', 'light', 'rushed'];
export const MEAL_KEYS: MealKey[] = ['breakfast', 'lunch', 'dinner', 'supper'];
export const DIFFICULTY_KEYS: DifficultyKey[] = ['easy', 'normal', 'hard'];
export const TASTE_KEYS: TasteKey[] = ['spicy', 'sweet', 'sour', 'savory'];

