// (fridge ingredients, check-in records, today's dish id). JSON values are
// stored as strings; a bare scalar (today's dish id) uses the string path.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';

const STORE_NAME: string = 'eatwhat_store';

export class LocalStore {
  private static instance: LocalStore | null = null;
  private prefs: preferences.Preferences | null = null;

  static getInstance(): LocalStore {
    if (LocalStore.instance === null) {
      LocalStore.instance = new LocalStore();
    }
    return LocalStore.instance;
  }

  async init(context: common.Context): Promise<void> {
    if (this.prefs !== null) {
      return;
    }
    try {
      this.prefs = await preferences.getPreferences(context, STORE_NAME);
    } catch (e) {
      this.prefs = null;
    }
  }

  isReady(): boolean {
    return this.prefs !== null;
  }

  private ensure(): preferences.Preferences | null {
    return this.prefs;
  }

  async readJSON<T>(key: string): Promise<T | null> {
    const p: preferences.Preferences | null = this.ensure();
    if (p === null) {
      return null;
    }
    try {
      const raw: string = (await p.get(key, '')) as string;
      if (raw === null || raw === '') {
        return null;
      }
      return JSON.parse(raw) as T;
    } catch (e) {
      return null;
    }
  }

  async writeJSON(key: string, value: object): Promise<void> {
    const p: preferences.Preferences | null = this.ensure();
    if (p === null) {
      return;
    }
    try {
      await p.put(key, JSON.stringify(value));
      await p.flush();
    } catch (e) {
    }
  }

  async readString(key: string): Promise<string | null> {
    const p: preferences.Preferences | null = this.ensure();
    if (p === null) {
      return null;
    }
    try {
      const raw: string = (await p.get(key, '')) as string;
      if (raw === null || raw === '') {
        return null;
      }
      return raw;
    } catch (e) {
      return null;
    }
  }

  async writeString(key: string, value: string): Promise<void> {
    const p: preferences.Preferences | null = this.ensure();
    if (p === null) {
      return;
    }
    try {
      await p.put(key, value);
      await p.flush();
    } catch (e) {
    }
  }

  async remove(key: string): Promise<void> {
    const p: preferences.Preferences | null = this.ensure();
    if (p === null) {
      return;
    }
    try {
      await p.delete(key);
      await p.flush();
    } catch (e) {
    }
  }
}

