// AppController.ets
//
// Central application controller. Wires services together and exposes the
// observable state + event methods that map 1:1 to the semantic events in
// .arkpilot/designs/ui-tree.json. The visual layer (added later) binds to
// these fields and methods; this file contains no layout.

import { common } from '@kit.AbilityKit';

import { Dish, MealKey, MoodKey, DifficultyKey, TasteKey,
  moodLabel, mealLabel, difficultyLabel, tasteLabel } from '../model/DishModel';
import { CheckinRecord } from '../model/CheckinModel';
import { FilterCriteria, ScoredDish, CalendarDay, ShareCard, emptyCriteria, isEmptyCriteria } from '../model/FilterModel';
import { DateUtil } from '../util/DateUtil';

import { LocalStore } from '../service/LocalStore';
import { DishService } from '../service/DishService';
import { FridgeService } from '../service/FridgeService';
import { CheckinService } from '../service/CheckinService';
import { ShareService } from '../service/ShareService';

const TODAY_DISH_KEY: string = 'today_dish_id';
const WHEEL_SIZE: number = 8;

type ResultSource = 'filter' | 'fridge';

export class AppController {
  private static instance: AppController | null = null;
  private store: LocalStore = LocalStore.getInstance();
  private fridge: FridgeService = FridgeService.getInstance();
  private checkins: CheckinService = CheckinService.getInstance();

  // ---- home ----
  greeting: string = '';
  todayDateLabel: string = '';
  todayDish: Dish | null = null;
  recentCheckins: CheckinRecord[] = [];

  // ---- spin ----
  wheelSegments: Dish[] = [];
  spinResult: Dish | null = null;

  // ---- fridge ----
  fridgeIngredients: string[] = [];

  // ---- filter / result ----
  criteria: FilterCriteria = emptyCriteria();
  resultSource: ResultSource = 'filter';
  private lastIngredients: string[] = [];
  recommendResults: ScoredDish[] = [];
  resultDishes: Dish[] = [];
  resultSummary: string = '';

  // ---- checkin ----
  checkinStreak: number = 0;
  checkinCalendar: CalendarDay[] = [];
  todayCheckin: CheckinRecord | null = null;
  checkinHistory: CheckinRecord[] = [];

  // ---- share ----
  shareCard: ShareCard | null = null;

  static getInstance(): AppController {
    if (AppController.instance === null) {
      AppController.instance = new AppController();
    }
    return AppController.instance;
  }

  async init(context: common.Context): Promise<void> {
    await this.store.init(context);
    await this.fridge.load();
    await this.checkins.load();

    const todayId: string | null = await this.store.readJSON<string>(TODAY_DISH_KEY);
    if (todayId !== null && todayId.length > 0) {
      this.todayDish = DishService.findById(todayId);
    }
    this.refreshHome();
    this.refreshFridge();
    this.refreshCheckin();
  }

  // ============ home ============
  refreshHome(): void {
    this.greeting = DateUtil.greetingFor();
    this.todayDateLabel = DateUtil.formattedToday();
    this.recentCheckins = this.checkins.recent(3);
    if (this.todayDish === null) {
      this.todayDish = DishService.pickRandom();
    }
  }

  // ============ spin (FR-1) ============
  openSpin(): void {
    this.wheelSegments = DishService.pickWheelSegments(WHEEL_SIZE);
    this.spinResult = null;
  }

  spinStart(): void {
    if (this.wheelSegments.length === 0) {
      this.openSpin();
    }
    const idx: number = Math.floor(Math.random() * this.wheelSegments.length);
    this.spinResult = this.wheelSegments[idx];
  }

  spinAgain(): void {
    this.spinStart();
  }

  spinConfirm(): void {
    if (this.spinResult !== null) {
      this.setTodayDish(this.spinResult);
    }
  }

  // ============ fridge (FR-2) ============
  refreshFridge(): void {
    this.fridgeIngredients = this.fridge.list();
  }

  ingredientAdd(raw: string): boolean {
    const ok: boolean = this.fridge.add(raw);
    this.refreshFridge();
    return ok;
  }

  ingredientRemoveAt(index: number): void {
    this.fridge.removeAt(index);
    this.refreshFridge();
  }

  ingredientClearAll(): void {
    this.fridge.clearAll();
    this.refreshFridge();
  }

  fridgeRecommend(): void {
    this.lastIngredients = this.fridge.list().slice();
    this.recommendResults = DishService.recommend(this.lastIngredients);
    this.resultDishes = this.recommendResults.map((s: ScoredDish) => s.dish);
    this.resultSource = 'fridge';
    const n: number = this.lastIngredients.length;
    const hits: number = this.resultDishes.length;
    this.resultSummary = n === 0
      ? '还没有添加食材'
      : `基于 ${n} 种食材，找到 ${hits} 道可做菜`;
  }

  // ============ filter (FR-3) ============
  filterMoodSelect(mood: MoodKey): void {
    this.criteria.mood = this.criteria.mood === mood ? null : mood;
  }

  filterMealSelect(meal: MealKey): void {
    this.criteria.meal = this.criteria.meal === meal ? null : meal;
  }

  filterDifficultySelect(d: DifficultyKey): void {
    this.criteria.difficulty = this.criteria.difficulty === d ? null : d;
  }

  filterTasteToggle(t: TasteKey): void {
    const idx: number = this.criteria.tastes.indexOf(t);
    if (idx >= 0) {
      this.criteria.tastes.splice(idx, 1);
    } else {
      this.criteria.tastes.push(t);
    }
  }

  filterReset(): void {
    this.criteria = emptyCriteria();
  }

  filterApply(): void {
    this.resultSource = 'filter';
    this.resultDishes = DishService.filter(this.criteria);
    this.recommendResults = [];
    this.resultSummary = this.buildFilterSummary();
  }

  private buildFilterSummary(): string {
    if (isEmptyCriteria(this.criteria)) {
      return '未设置筛选条件，为你展示全部菜品';
    }
    const parts: string[] = [];
    if (this.criteria.mood !== null) {
      parts.push(moodLabel(this.criteria.mood));
    }
    if (this.criteria.meal !== null) {
      parts.push(mealLabel(this.criteria.meal));
    }
    if (this.criteria.difficulty !== null) {
      parts.push(difficultyLabel(this.criteria.difficulty));
    }
    for (const t of this.criteria.tastes) {
      parts.push(tasteLabel(t));
    }
    return `${parts.join(' · ')} · 共 ${this.resultDishes.length} 道`;
  }

  // ============ result ============
  resultRefresh(): void {
    if (this.resultSource === 'fridge') {
      this.recommendResults = DishService.recommend(this.lastIngredients);
      this.resultDishes = this.recommendResults.map((s: ScoredDish) => s.dish);
    } else {
      this.resultDishes = DishService.filter(this.criteria);
    }
  }

  resultPick(dish: Dish): void {
    this.setTodayDish(dish);
  }

  // ============ checkin (FR-4) ============
  refreshCheckin(): void {
    this.checkinStreak = this.checkins.streak();
    this.checkinCalendar = this.checkins.calendar();
    this.todayCheckin = this.checkins.todayLatest();
    this.checkinHistory = this.checkins.history();
  }

  checkinAdd(meal: MealKey, dishName: string, note: string, dateKey: string = ''): CheckinRecord | null {
    const rec: CheckinRecord | null = this.checkins.add(dateKey, meal, dishName, note);
    if (rec !== null) {
      this.refreshCheckin();
      this.recentCheckins = this.checkins.recent(3);
    }
    return rec;
  }

  checkinDelete(id: string): void {
    this.checkins.remove(id);
    this.refreshCheckin();
    this.recentCheckins = this.checkins.recent(3);
  }

  // ============ share (FR-5) ============
  openShare(): ShareCard {
    const dishName: string = this.todayCheckin !== null
      ? this.todayCheckin.dishName
      : (this.todayDish !== null ? this.todayDish.name : '今日美味');
    this.shareCard = ShareService.buildCard(
      DateUtil.formattedToday(),
      dishName,
      this.checkinStreak,
      'sage',
    );
    return this.shareCard;
  }

  async shareSaveImage(): Promise<boolean> {
    const ok: boolean = await ShareService.saveImage();
    if (ok && this.todayCheckin !== null) {
      this.checkins.markShared(this.todayCheckin.id);
      this.refreshCheckin();
    }
    return ok;
  }

  async shareSystem(): Promise<boolean> {
    return ShareService.systemShare();
  }

  // ============ shared helpers ============
  private setTodayDish(dish: Dish): void {
    this.todayDish = dish;
    this.store.writeJSON(TODAY_DISH_KEY, dish.id as object).catch(() => {});
  }
}

